#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        int mx = a;
        if (b > mx) mx = b;
        if (c > mx) mx = c;
        printf("Largest: %d\n", mx);
    }
    return 0;
}

