import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it)); c = int(next(it))
        mx = a
        if b > mx:
            mx = b
        if c > mx:
            mx = c
        out.append(f"Largest: {mx}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

